            TASK_TYPE_CACHE_CLEAR -> processCacheClear(intent, taskId, taskInfo)
            TASK_TYPE_DB_OPTIMIZE -> processDbOptimize(intent, taskId, taskInfo)
            TASK_TYPE_LOG_CLEANUP -> processLogCleanup(intent, taskId, taskInfo)
            else -> {
                Log.w(TAG, "Unknown task type: $taskType")
                taskInfo.status = TaskStatus.FAILED
                broadcastTaskFailed(taskId, 100, "Unknown task type: $taskType", taskInfo)
                return
            }
        }
    }

