    private fun cleanTemporaryFiles(olderThanDays: Int): Long {
        Log.d(TAG, "Cleaning temporary files older than $olderThanDays days")
        Thread.sleep(800)

        var cleaned = 0L
        val cacheDir = cacheDir
        if (cacheDir.exists()) {
            val cutoffTime = System.currentTimeMillis() - (olderThanDays * 24 * 60 * 60 * 1000L)
            cacheDir.listFiles()?.forEach { file ->
                if (file.lastModified() < cutoffTime) {
                    val size = file.length()
                    if (file.delete()) {
                        cleaned += size
