    private fun runVacuum(dbName: String?) {
        Log.d(TAG, "Running VACUUM on: ${dbName ?: "all databases"}")
        Thread.sleep(1000)

        val databases = if (dbName != null) listOf(dbName) else databaseList().toList()
        databases.forEach { db ->
            try {
                val database = openOrCreateDatabase(db, MODE_PRIVATE, null)
                database.execSQL("VACUUM")
                database.close()
                Log.d(TAG, "VACUUM completed for: $db")
            } catch (e: Exception) {
                Log.w(TAG, "Failed to VACUUM $db: ${e.message}")
            }
        }
    }

    private fun runReindex(dbName: String?) {
        Log.d(TAG, "Running REINDEX on: ${dbName ?: "all databases"}")
