        Thread.sleep(400)

        val databases = if (dbName != null) listOf(dbName) else databaseList().toList()
        databases.forEach { db ->
            try {
                val database = openOrCreateDatabase(db, MODE_PRIVATE, null)
                database.execSQL("ANALYZE")
                database.close()
            } catch (e: Exception) {
