            }
        }
    }

    private fun checkDatabaseIntegrity(dbName: String?): Boolean {
        Log.d(TAG, "Checking database integrity")
        Thread.sleep(600)

        val databases = if (dbName != null) listOf(dbName) else databaseList().toList()
        var allOk = true

        databases.forEach { db ->
            try {
                val database = openOrCreateDatabase(db, MODE_PRIVATE, null)
                val cursor = database.rawQuery("PRAGMA integrity_check", null)
                if (cursor.moveToFirst()) {
                    val result = cursor.getString(0)
                    if (result != "ok") {
                        allOk = false
                        Log.w(TAG, "Integrity check failed for $db: $result")
                    }
                }
                cursor.close()
                database.close()
            } catch (e: Exception) {
                Log.w(TAG, "Failed integrity check for $db: ${e.message}")
                allOk = false
            }
        }
        return allOk
    }

