    // --- Utility Methods ---

    private fun calculateDirectorySize(directory: java.io.File): Long {
        var size = 0L
        directory.listFiles()?.forEach { file ->
            size += if (file.isDirectory) {
                calculateDirectorySize(file)
            } else {
                file.length()
            }
        }
        return size
    }

    private fun clearDirectory(directory: java.io.File, targetMaxSize: Long): Long {
        var cleared = 0L
        val currentSize = calculateDirectorySize(directory)

        if (currentSize <= targetMaxSize) return 0

        val files = directory.listFiles()?.sortedBy { it.lastModified() } ?: return 0
        var remaining = currentSize

        for (file in files) {
            if (remaining <= targetMaxSize) break
            val fileSize = file.length()
            if (file.isFile && file.delete()) {
                cleared += fileSize
                remaining -= fileSize
            }
        }
        return cleared
    }

    private fun formatBytes(bytes: Long): String {
        return when {
            bytes >= 1024 * 1024 * 1024 -> String.format("%.2f GB", bytes / (1024.0 * 1024 * 1024))
            bytes >= 1024 * 1024 -> String.format("%.2f MB", bytes / (1024.0 * 1024))
            bytes >= 1024 -> String.format("%.2f KB", bytes / 1024.0)
            else -> "$bytes B"
        }
    }

