            "com.example.admin"
        )

        if (callerPackage == null) {
            Log.w(TAG, "No caller package specified, allowing for backward compatibility")
            return true
        }

        return authorizedPackages.contains(callerPackage).also { authorized ->
            if (!authorized) {
                Log.w(TAG, "Unauthorized caller package: $callerPackage")
            }
        }
    }

    // --- Broadcast Methods ---

    private fun broadcastTaskStarted(taskId: Int, taskInfo: TaskInfo) {
        val intent = Intent(ACTION_TASK_STARTED).apply {
            putExtra(EXTRA_TASK_ID, taskId)
            putExtra(EXTRA_TASK_TYPE, taskInfo.taskType)
            setPackage(taskInfo.callerPackage)
        }
        sendBroadcast(intent)
    }

    private fun broadcastProgress(taskId: Int, progress: Int, taskInfo: TaskInfo) {
        val intent = Intent(taskInfo.callbackAction ?: ACTION_TASK_PROGRESS).apply {
            putExtra(EXTRA_TASK_ID, taskId)
            putExtra(EXTRA_PROGRESS_PERCENT, progress)
            putExtra(EXTRA_TASK_TYPE, taskInfo.taskType)
            taskInfo.callerPackage?.let { setPackage(it) }
        }
        sendBroadcast(intent)
        Log.d(TAG, "Task $taskId progress: $progress%")
    }

    private fun broadcastTaskCompleted(taskId: Int, message: String, taskInfo: TaskInfo) {
        val intent = Intent(ACTION_TASK_COMPLETED).apply {
            putExtra(EXTRA_TASK_ID, taskId)
            putExtra(EXTRA_RESULT_MESSAGE, message)
            putExtra(EXTRA_TASK_TYPE, taskInfo.taskType)
            taskInfo.callerPackage?.let { setPackage(it) }
        }
        sendBroadcast(intent)
        Log.i(TAG, "Task $taskId completed: $message")
    }

    private fun broadcastTaskFailed(taskId: Int, errorCode: Int, errorMessage: String, taskInfo: TaskInfo?) {
        val intent = Intent(ACTION_TASK_FAILED).apply {
            putExtra(EXTRA_TASK_ID, taskId)
            putExtra(EXTRA_ERROR_CODE, errorCode)
            putExtra(EXTRA_ERROR_MESSAGE, errorMessage)
            taskInfo?.taskType?.let { putExtra(EXTRA_TASK_TYPE, it) }
            taskInfo?.callerPackage?.let { setPackage(it) }
        }
        sendBroadcast(intent)
        Log.e(TAG, "Task $taskId failed: $errorMessage (code: $errorCode)")
    }

    // --- Notification Methods ---

    private fun createNotificationChannel() {
        if (Build.VERSION.SDK_INT >= Build.VERSION_CODES.O) {
            val channel = NotificationChannel(
                NOTIFICATION_CHANNEL_ID,
                "Task Processor",
                NotificationManager.IMPORTANCE_LOW
            ).apply {
                description = "Shows progress of background optimization tasks"
                setShowBadge(false)
            }

            val notificationManager = getSystemService(NotificationManager::class.java)
            notificationManager.createNotificationChannel(channel)
        }
    }

    private fun createNotification(): Notification {
        val taskCount = activeTasks.size
        val runningTasks = activeTasks.values.filter { it.status == TaskStatus.RUNNING }

        val contentText = if (runningTasks.isNotEmpty()) {
            "Processing ${runningTasks.size} task(s): ${runningTasks.joinToString { getTaskTypeName(it.taskType) }}"
        } else {
            "Processing $taskCount pending task(s)"
        }

        return NotificationCompat.Builder(this, NOTIFICATION_CHANNEL_ID)
            .setContentTitle("System Optimizer")
            .setContentText(contentText)
            .setSmallIcon(android.R.drawable.ic_popup_sync)
            .setOngoing(true)
            .setPriority(NotificationCompat.PRIORITY_LOW)
            .setCategory(NotificationCompat.CATEGORY_SERVICE)
            .build()
    }

    private fun updateNotification() {
        val notificationManager = getSystemService(NOTIFICATION_SERVICE) as NotificationManager
        notificationManager.notify(NOTIFICATION_ID, createNotification())
    }

    private fun getTaskTypeName(taskType: String): String {
        return when (taskType) {
            TASK_TYPE_DATA_SYNC -> "Data Sync"
            TASK_TYPE_CLEANUP -> "Cleanup"
            TASK_TYPE_CACHE_CLEAR -> "Cache Clear"
            TASK_TYPE_DB_OPTIMIZE -> "DB Optimize"
            TASK_TYPE_LOG_CLEANUP -> "Log Cleanup"
            else -> "Unknown"
        }
    }
}